import{_ as t,o,c as s,a2 as a}from"./chunks/framework.C69UpXSI.js";const h=JSON.parse('{"title":"Tools","description":"","frontmatter":{},"headers":[],"relativePath":"en/agents/tools.md","filePath":"en/agents/tools.md"}'),i={name:"en/agents/tools.md"};function n(d,e,r,c,l,p){return o(),s("div",null,[...e[0]||(e[0]=[a(`<h1 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h1><p>Tools available to TurboDev agents.</p><p>Agents have access to a set of tools for interacting with your codebase. Tool availability can be controlled per-agent via the <code>tools</code> configuration.</p><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th></tr></thead><tbody><tr><td><code>bash</code></td><td>Execute shell commands</td></tr><tr><td><code>edit_file</code></td><td>Create or edit files</td></tr><tr><td><code>git</code></td><td>Execute Git operations</td></tr><tr><td><code>github</code></td><td>Execute GitHub operations</td></tr><tr><td><code>grep</code></td><td>Search file contents with regex</td></tr><tr><td><code>list_files</code></td><td>List directory contents</td></tr><tr><td><code>mkdir</code></td><td>Create directories</td></tr><tr><td><code>question</code></td><td>Ask the user a question</td></tr><tr><td><code>read_file</code></td><td>Read file contents</td></tr><tr><td><code>load_skill</code></td><td>Load skill instructions or resource files</td></tr><tr><td><code>save_memory</code></td><td>Save a durable fact to persistent memory</td></tr><tr><td><code>task</code></td><td>Invoke a subagent</td></tr></tbody></table><h2 id="read-file" tabindex="-1">read_file <a class="header-anchor" href="#read-file" aria-label="Permalink to &quot;read_file&quot;">​</a></h2><p>Read the full content of a file.</p><p><strong>Args</strong>: <code>{ path: string }</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>read_file({ &quot;path&quot;: &quot;src/index.ts&quot; })</span></span></code></pre></div><h2 id="edit-file" tabindex="-1">edit_file <a class="header-anchor" href="#edit-file" aria-label="Permalink to &quot;edit_file&quot;">​</a></h2><p>Create or edit a file. If <code>old_str</code> is empty, creates the file with <code>new_str</code>. Otherwise, finds and replaces the first occurrence of <code>old_str</code> with <code>new_str</code>.</p><p><strong>Args</strong>: <code>{ path: string, old_str: string, new_str: string }</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>edit_file({ &quot;path&quot;: &quot;src/app.ts&quot;, &quot;old_str&quot;: &quot;hello&quot;, &quot;new_str&quot;: &quot;world&quot; })</span></span></code></pre></div><h2 id="list-files" tabindex="-1">list_files <a class="header-anchor" href="#list-files" aria-label="Permalink to &quot;list_files&quot;">​</a></h2><p>List files and directories in a given path.</p><p><strong>Args</strong>: <code>{ path?: string }</code> (defaults to current directory)</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>list_files({ &quot;path&quot;: &quot;src&quot; })</span></span></code></pre></div><h2 id="mkdir" tabindex="-1">mkdir <a class="header-anchor" href="#mkdir" aria-label="Permalink to &quot;mkdir&quot;">​</a></h2><p>Create a new directory, including parent directories.</p><p><strong>Args</strong>: <code>{ path: string }</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mkdir({ &quot;path&quot;: &quot;src/components/ui&quot; })</span></span></code></pre></div><h2 id="grep" tabindex="-1">grep <a class="header-anchor" href="#grep" aria-label="Permalink to &quot;grep&quot;">​</a></h2><p>Search file contents using regular expressions.</p><p><strong>Args</strong>: <code>{ pattern: string, include?: string, path?: string }</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>grep({ &quot;pattern&quot;: &quot;TODO&quot;, &quot;include&quot;: &quot;*.ts&quot; })</span></span></code></pre></div><h2 id="bash" tabindex="-1">bash <a class="header-anchor" href="#bash" aria-label="Permalink to &quot;bash&quot;">​</a></h2><p>Execute a shell command and return output.</p><p><strong>Args</strong>: <code>{ command: string, timeout?: number, workdir?: string }</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bash({ &quot;command&quot;: &quot;npm test&quot;, &quot;timeout&quot;: 60000 })</span></span></code></pre></div><h2 id="question" tabindex="-1">question <a class="header-anchor" href="#question" aria-label="Permalink to &quot;question&quot;">​</a></h2><p>Ask the user a question and wait for their response.</p><p><strong>Args</strong>: <code>{ question: string, options?: string[] }</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>question({ &quot;question&quot;: &quot;Which framework?&quot;, &quot;options&quot;: [&quot;react&quot;, &quot;vue&quot;] })</span></span></code></pre></div><h2 id="load-skill" tabindex="-1">load_skill <a class="header-anchor" href="#load-skill" aria-label="Permalink to &quot;load_skill&quot;">​</a></h2><p>Load full instructions or a specific resource file from an agent skill. The LLM calls this automatically when it determines a skill is relevant to the current task.</p><p><strong>Args</strong>: <code>{ name: string, resource?: string }</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>load_skill({ &quot;name&quot;: &quot;react-component&quot; })</span></span>
<span class="line"><span>load_skill({ &quot;name&quot;: &quot;react-component&quot;, &quot;resource&quot;: &quot;references/patterns.md&quot; })</span></span></code></pre></div><p>When <code>resource</code> is omitted, returns the full SKILL.md instructions. When provided, returns the content of the specified file within the skill directory.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>This tool is always enabled and cannot be disabled per-agent. The LLM only has access to skill metadata in the system prompt until it calls <code>load_skill</code>.</p></div><h2 id="save-memory" tabindex="-1">save_memory <a class="header-anchor" href="#save-memory" aria-label="Permalink to &quot;save_memory&quot;">​</a></h2><p>Save a durable fact to persistent memory (<code>.turbodev/memory.md</code>) for future sessions. The LLM calls this when it learns something worth remembering.</p><p><strong>Args</strong>: <code>{ content: string, category?: string }</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>save_memory({ &quot;content&quot;: &quot;User prefers pnpm over npm&quot;, &quot;category&quot;: &quot;preferences&quot; })</span></span>
<span class="line"><span>save_memory({ &quot;content&quot;: &quot;Project uses PostgreSQL 16&quot; })</span></span></code></pre></div><p>Categories: <code>preferences</code>, <code>decisions</code>, <code>architecture</code>, <code>facts</code> (default). Only save information relevant to <strong>future</strong> sessions — not transient task state.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>This tool is always enabled and writes only to <code>.turbodev/memory.md</code> (gitignored). It cannot modify other files. Memory survives compaction because it lives in the system prompt.</p></div><p>See <a href="/turbodev/en/configuration/memory.html">Persistent Memory</a> for the full reference.</p><h2 id="task" tabindex="-1">task <a class="header-anchor" href="#task" aria-label="Permalink to &quot;task&quot;">​</a></h2><p>Invoke a subagent for a specialized task.</p><p><strong>Args</strong>: <code>{ agent: string, prompt: string, description: string }</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>task({ &quot;agent&quot;: &quot;explore&quot;, &quot;prompt&quot;: &quot;find all API routes&quot;, &quot;description&quot;: &quot;Explore API routes&quot; })</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The <code>task</code> tool is disabled for the plan agent by default.</p></div><h2 id="git" tabindex="-1">git <a class="header-anchor" href="#git" aria-label="Permalink to &quot;git&quot;">​</a></h2><p>Execute Git operations via simple-git. Supports 26 operations including status, log, diff, add, commit, push, pull, branch, stash, remote, and more.</p><p><strong>Args</strong>: <code>{ operation: string, args?: any }</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git({ &quot;operation&quot;: &quot;status&quot; })</span></span>
<span class="line"><span>git({ &quot;operation&quot;: &quot;log&quot;, &quot;args&quot;: { &quot;maxCount&quot;: 10 } })</span></span>
<span class="line"><span>git({ &quot;operation&quot;: &quot;commit&quot;, &quot;args&quot;: { &quot;message&quot;: &quot;fix: resolve bug&quot; } })</span></span></code></pre></div><p>Available operations: <code>status</code>, <code>log</code>, <code>diff</code>, <code>add</code>, <code>commit</code>, <code>push</code>, <code>pull</code>, <code>branch</code>, <code>checkout</code>, <code>stash</code>, <code>remote</code>, <code>fetch</code>, <code>reset</code>, <code>revert</code>, <code>tag</code>, <code>merge</code>, <code>rebase</code>, <code>init</code>, <code>clone</code>, <code>addRemote</code>, <code>removeRemote</code>, <code>listRemotes</code>, <code>raw</code>, <code>diffSummary</code>, <code>show</code>, <code>clean</code>.</p><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>Git operations that modify the repository (commit, push, reset, revert, clean, etc.) require explicit permission from the user.</p></div><h2 id="github" tabindex="-1">github <a class="header-anchor" href="#github" aria-label="Permalink to &quot;github&quot;">​</a></h2><p>Execute GitHub operations via the <code>gh</code> CLI. Supports 15 operations including PR management, issues, releases, and authentication.</p><p><strong>Args</strong>: <code>{ operation: string, args?: any }</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>github({ &quot;operation&quot;: &quot;createPr&quot;, &quot;args&quot;: { &quot;title&quot;: &quot;Fix bug&quot;, &quot;body&quot;: &quot;Description&quot; } })</span></span>
<span class="line"><span>github({ &quot;operation&quot;: &quot;listPrs&quot; })</span></span>
<span class="line"><span>github({ &quot;operation&quot;: &quot;createIssue&quot;, &quot;args&quot;: { &quot;title&quot;: &quot;Bug report&quot;, &quot;body&quot;: &quot;Steps to reproduce&quot; } })</span></span></code></pre></div><p>Available operations: <code>authStatus</code>, <code>createPr</code>, <code>listPrs</code>, <code>viewPr</code>, <code>mergePr</code>, <code>closePr</code>, <code>createIssue</code>, <code>listIssues</code>, <code>closeIssue</code>, <code>createRelease</code>, <code>listReleases</code>, <code>repoView</code>, <code>repoClone</code>, <code>runList</code>, <code>runView</code>.</p><p>Requires the <a href="https://cli.github/" target="_blank" rel="noreferrer">GitHub CLI (<code>gh</code>)</a> to be installed and authenticated. Run <code>/gh auth</code> to set up authentication.</p><h2 id="controlling-tool-access" tabindex="-1">Controlling Tool Access <a class="header-anchor" href="#controlling-tool-access" aria-label="Permalink to &quot;Controlling Tool Access&quot;">​</a></h2><p>Tools can be enabled or disabled per-agent in the Markdown configuration:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  edit_file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  bash</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  task</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p>When a tool is disabled (<code>false</code>), the agent receives an error if it tries to use it: <code>Tool &quot;edit_file&quot; is denied for agent &quot;plan&quot;</code>.</p><h2 id="mcp-tools-dynamic" tabindex="-1">MCP Tools (dynamic) <a class="header-anchor" href="#mcp-tools-dynamic" aria-label="Permalink to &quot;MCP Tools (dynamic)&quot;">​</a></h2><p>In addition to the native tools above, agents can invoke <strong>MCP tools</strong> registered dynamically from external MCP servers declared in <code>.turbodev/mcp.json</code>. These tools appear automatically in the system prompt when at least one server is connected.</p><p>MCP tool names follow the convention <code>mcp__&lt;server&gt;__&lt;tool&gt;</code> — for example, a <code>filesystem</code> server exposing a <code>read_file</code> tool is callable as:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tool: mcp__filesystem__read_file({&quot;path&quot;: &quot;/tmp/example.txt&quot;})</span></span></code></pre></div><p>MCP tools are not listed in the <code>tools:</code> config (they&#39;re dynamic). To disable a specific MCP tool, use its full prefixed name:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;mcp__filesystem__delete&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p>Permissions for MCP tools default to <code>ask</code> and are configured via <code>permission.mcp</code>. See <a href="/turbodev/en/agents/permissions.html#mcp-tools">Permissions</a> and <a href="/turbodev/en/configuration/mcp.html">MCP configuration</a> for details.</p><p><a href="/turbodev/en/agents/permissions.html">Learn more about permissions</a></p>`,75)])])}const g=t(i,[["render",n]]);export{h as __pageData,g as default};
